class QueryBuilder {
  static buildInsert(table, data) {
    validateTableName(table);
    const columns = Object.keys(data);
    validateColumnNames(table, columns);

    const values = columns.map((col) => sanitizeValue(data[col]));
    const placeholders = columns.map((_, i) => `$${i + 1}`);

    const query = `INSERT INTO ${table} (${columns.join(', ')}) VALUES (${placeholders.join(', ')}) RETURNING *`;
    return { query, values };
  }

  static buildUpdate(table, data, conditions) {
    validateTableName(table);
    const updateColumns = Object.keys(data);
    const conditionColumns = Object.keys(conditions);
    validateColumnNames(table, [...updateColumns, ...conditionColumns]);

    let paramIndex = 1;
    const setClauses = updateColumns.map((col) => `${col} = $${paramIndex++}`);
    const whereClauses = conditionColumns.map((col) => `${col} = $${paramIndex++}`);

    const values = [
      ...updateColumns.map((col) => sanitizeValue(data[col])),
      ...conditionColumns.map((col) => sanitizeValue(conditions[col])),
    ];

    const query = `UPDATE ${table} SET ${setClauses.join(', ')} WHERE ${whereClauses.join(' AND ')} RETURNING *`;
    return { query, values };
  }

  static buildDelete(table, conditions) {
    validateTableName(table);
    const conditionColumns = Object.keys(conditions);
    validateColumnNames(table, conditionColumns);

    let paramIndex = 1;
    const whereClauses = conditionColumns.map((col) => `${col} = $${paramIndex++}`);
    const values = conditionColumns.map((col) => sanitizeValue(conditions[col]));

    const query = `DELETE FROM ${table} WHERE ${whereClauses.join(' AND ')} RETURNING *`;
    return { query, values };
  }

  static buildSelect(table, conditions, options = {}) {
    validateTableName(table);
    const conditionColumns = Object.keys(conditions);
    validateColumnNames(table, conditionColumns);

    let paramIndex = 1;
    const whereClauses = conditionColumns.map((col) => `${col} = $${paramIndex++}`);
    const values = conditionColumns.map((col) => sanitizeValue(conditions[col]));

    let query = `SELECT * FROM ${table}`;
    if (whereClauses.length > 0) {
      query += ` WHERE ${whereClauses.join(' AND ')}`;
    }

    if (options.orderBy && ALLOWED_COLUMNS[table]?.includes(options.orderBy)) {
      const direction = options.orderDirection === 'DESC' ? 'DESC' : 'ASC';
      query += ` ORDER BY ${options.orderBy} ${direction}`;
    }

    if (options.limit && Number.isInteger(options.limit) && options.limit > 0) {
      query += ` LIMIT $${paramIndex++}`;
      values.push(options.limit);
    }

    if (options.offset && Number.isInteger(options.offset) && options.offset >= 0) {
      query += ` OFFSET $${paramIndex++}`;
      values.push(options.offset);
    }

    return { query, values };
  }
}

